B.a38=new A.br("\u0130leri/Geri y\xf6n","Arac\u0131n ileri y\xf6n\xfcn\xfc d\xfczeltir. +1 standart: ROS-pozitif vx arac\u0131 ileri s\xfcrer. -1: motor kablolar\u0131/\u015fase ters montajl\u0131ysa veya pozitif vx arac\u0131 geri g\xf6t\xfcr\xfcyorsa.","Yanl\u0131\u015fsa: ileri komutu geri gidiyor (veya tersi)",null,-1,1,"Y\xf6n Kalibrasyonu")
B.a2G=new A.br("Direksiyon y\xf6n\xfc","Direksiyon (servo) y\xf6n\xfcn\xfc d\xfczeltir. Sol komutu (pozitif wz) arac\u0131 sa\u011fa \xe7eviriyorsa bu de\u011feri -1 yap. Linkage mekanik geometrisine ba\u011fl\u0131.","Yanl\u0131\u015fsa: sol komut sa\u011fa d\xf6n\xfc\u015f yapar",null,-1,1,"Y\xf6n Kalibrasyonu")
B.a2m=new A.br("Geri vites direksiyon y\xf6n\xfc","Sadece geri viteste direksiyon y\xf6n\xfcn\xfc \xe7evirir. REEDS_SHEPP planner geriye-ileri cusp'larda direksiyon hissini korumak i\xe7in kullan\u0131l\u0131r. Forward y\xf6n do\u011fruysa, reverse'de tekerlekler ters tarafa bak\u0131yorsa -1 yap.",null,null,-1,1,"Y\xf6n Kalibrasyonu")
B.a2s=new A.br("Max ileri h\u0131z","Bridge'in kabul edece\u011fi max ileri h\u0131z. Bunun \xfcst\xfcndeki Nav2 komutlar\u0131 k\u0131rp\u0131l\u0131r. Nav2'nin desired_linear_vel'i bunun alt\u0131nda olmal\u0131 (yoksa bridge kesip atar).","\u2191 daha h\u0131zl\u0131 ama precision azal\u0131r","m/s",0.1,0.5,"H\u0131z Limitleri")
B.a2t=new A.br("Max a\xe7\u0131sal h\u0131z",'Max yaw rate limiti. \xc7ok y\xfcksek de\u011fer servo\'nun fiziksel yapamad\u0131\u011f\u0131 d\xf6n\xfc\u015f iste\u011fine yol a\xe7ar \u2192 "thunk" sesi + stale steering.',"\u2191 daha keskin d\xf6n\xfc\u015f, \u2193 yumu\u015fak d\xf6n\xfc\u015f","rad/s",0.3,1.5,"H\u0131z Limitleri")
B.a36=new A.br("Lineer ivme cap'i","Bridge'in tek tick'te uygulayabilece\u011fi max lineer ivme. Velocity smoother'dan gelen aggressive komutlara kar\u015f\u0131 son katman cap.","\u2193 yumu\u015fak ivmelenme (snake azal\u0131r), \u2191 h\u0131zl\u0131 tepki","m/s\xb2",0.2,1.5,"\u0130vme Limitleri")
B.a2g=new A.br("A\xe7\u0131sal ivme cap'i","Tek tick'te uygulanabilen max yaw ivmesi. Goal etraf\u0131nda osilasyonu ve servo jitter'\u0131n\u0131 azalt\u0131r.","\u2193 yumu\u015fak d\xf6n\xfc\u015f ba\u015flang\u0131c\u0131 (oscillation azal\u0131r)","rad/s\xb2",0.3,2,"\u0130vme Limitleri")
B.a2n=new A.br("Servo slew rate","Servo a\xe7\u0131s\u0131n\u0131n de\u011fi\u015fim h\u0131z\u0131 s\u0131n\u0131r\u0131. MG995 i\xe7in ~2.0-2.7 rad/s ger\xe7ek\xe7i. \xc7ok y\xfcksek olursa servo iste\u011fi yeti\u015ftiremez, \xe7ok d\xfc\u015f\xfck olursa direksiyon tepkisi gecikir.","\u2193 yumu\u015fak direksiyon, \u2191 keskin (servo zorlanabilir)","rad/s",1,4,"Direksiyon")
B.a2j=new A.br("Min creep h\u0131z\u0131","Bu mutlak h\u0131z\u0131n alt\u0131ndaki vx komutlar\u0131 0'a clip'lenir. L298N motor s\xfcr\xfcc\xfcs\xfcn\xfcn static-friction deadband'ini a\u015famayan komutlar\u0131n gereksiz titre\u015fim yapmas\u0131n\u0131 \xf6nler. Goal yakla\u015f\u0131m\u0131nda micro-lurching'i kald\u0131r\u0131r.","\u2191 goal'a daha temiz oturma, \u2193 daha d\xfc\u015f\xfck h\u0131zda creep m\xfcmk\xfcn","m/s",0,0.1,"Deadband")
