B.a2z=new A.br("Min carrot mesafesi","D\xfc\u015f\xfck h\u0131zda bile carrot bu mesafeden yak\u0131na inmez. Robot footprint'inin yar\u0131-uzunlu\u011fundan B\xdcY\xdcK olmal\u0131 (footprint yar\u0131s\u0131 0.15m \u2192 en az 0.18-0.20). Yoksa carrot kendi i\xe7inde kal\u0131r \u2192 snake.","\u2191 snake azal\u0131r, \u2193 daha tight tracking ama oscillation","m",0.15,0.3,"Carrot / Lookahead")
B.a2Y=new A.br("Max carrot mesafesi","Y\xfcksek h\u0131zda bile carrot bu mesafeden uza\u011fa \xe7\u0131kmaz. \xc7ok b\xfcy\xfck \u2192 ara\xe7 k\u0131sa path'lerde carrot'\u0131 path sonuna f\u0131rlat\u0131r, corner cut yapar.","\u2191 uzun d\xfcz path'te smooth, \u2193 goal yak\u0131n\u0131nda tight","m",0.25,0.6,"Carrot / Lookahead")
