B.a34=new A.br("Curvature carrot mesafesi","Direksiyon komutu hesab\u0131 i\xe7in AYRI carrot. Steering smooth'lu\u011funu kontrol eder. Genelde lookahead_dist ile ayn\u0131 veya yak\u0131n de\u011fer tutulur.","\u2191 smooth direksiyon, \u2193 keskin response","m",0.15,0.3,"Carrot / Lookahead")
B.a2X=new A.br("Curve yava\u015flama e\u015fi\u011fi","Path'in curvature yar\u0131\xe7ap\u0131 bu de\u011ferden k\xfc\xe7\xfckse RPP h\u0131z\u0131 azalt\u0131r. Planner'\u0131n minimum_turning_radius'undan b\xfcy\xfck olmal\u0131 (~1.4\xd7 iyi bir \xe7arpan).","\u2191 tight curve'lerde daha agresif yava\u015flama, \u2193 sabit h\u0131z","m",0.4,2,"E\u011fri / Cost Yava\u015flatma")
