B.a2l=new A.br("Cost yava\u015flama \u015fiddeti","Costmap inflation yak\u0131nl\u0131\u011f\u0131na ne kadar agresif yava\u015flanaca\u011f\u0131 (0-1 aras\u0131). Y\xfcksek (~1.0) \u2192 wall yak\u0131n\u0131 snake-stop. D\xfc\u015f\xfck (0.5-0.7) \u2192 smooth ge\xe7i\u015f.","\u2193 smooth (snake azal\u0131r), \u2191 wall'lardan \xe7ok ka\xe7\u0131nma",null,0.3,1,"E\u011fri / Cost Yava\u015flatma")
B.a2O=new A.br("RPP collision predict s\xfcresi",'RPP path boyunca bu kadar saniye ileriye forward simulate eder, collision g\xf6r\xfcrse h\u0131z\u0131 SIFIRLAR. Y\xfcksek (>1.0s) \u2192 duvar yan\u0131nda "plan var hareket yok" sendromu. D\xfc\u015f\xfck (0.5-0.7s) \u2192 daha cesur ama ger\xe7ek tehlike alg\u0131lans\u0131n diye yine de aktif kals\u0131n.',"\u2193 duvar yan\u0131nda stall azal\u0131r, \u2191 daha defensif","s",0.3,1.5,"Collision")
