B.a3_=new A.br("Curve cezas\u0131","Curve'ler d\xfcz \xe7izgilere kar\u015f\u0131 bu kadar pahal\u0131. Y\xfcksek (\u22651.2) \u2192 planner d\xfcz path tercih eder. R_min wide oldu\u011funda d\xfc\u015f\xfcrmek (1.05) curve'lere izin verir \u2192 engel etraf\u0131ndan dola\u015fma kolayla\u015f\u0131r.","\u2191 d\xfcz path bias, \u2193 planner daha rahat curve eder",null,1,1.5,"Search Penalties")
B.a2r=new A.br("Costmap cost cezas\u0131","Costmap'teki y\xfcksek-cost h\xfccrelerden (inflation, engel yak\u0131n\u0131) ka\xe7\u0131nma \u015fiddeti.","\u2191 engellerden daha \xe7ok ka\xe7\u0131n, \u2193 tight ge\xe7i\u015flere izin ver",null,1,3,"Search Penalties")
B.a39=new A.br("Analytic expansion oran\u0131","Planner heuristic'i bu orana ula\u015f\u0131nca Reeds-Shepp ile direkt closing dener. D\xfc\u015f\xfck (2.0-2.5) \u2192 final segment k\u0131sa ve temiz. Y\xfcksek \u2192 planner daha \xe7ok grid expansion yapar ama final segment uzun olabilir.","\u2193 park manevras\u0131nda k\u0131sa final, \u2191 daha kapsaml\u0131 arama",null,1.5,5,"Search")
B.a33=new A.br("Max planlama s\xfcresi","Planner'a verilen max s\xfcre. A\u015f\u0131l\u0131rsa fail. 2x2m testbed i\xe7in 2.0s yeterli.","\u2191 karma\u015f\u0131k plan'lara f\u0131rsat, \u2193 daha h\u0131zl\u0131 fail","s",1,5,"Search")
B.a0v=new A.bP(B.a1g,[B.a2i,B.a2B,B.a2S,B.a3_,B.a2r,B.a39,B.a33],t.h_)
B.a1r={max_velocity:0,min_velocity:1,max_accel:2,max_decel:3,smoothing_frequency:4}
B.a37=new A.br("Max h\u0131z vekt\xf6r\xfc [vx, vy, wz]","Smoother'\u0131n izin verdi\u011fi max h\u0131zlar. Format: [lineer m/s, yan m/s (0), a\xe7\u0131sal rad/s]. vx controller'\u0131n desired_linear_vel'i ile veya biraz \xfcst\xfcnde olmal\u0131.","Liste \u2014 virg\xfclle ay\u0131rarak gir",null,null,null,"H\u0131z Cap")
B.a2Z=new A.br("Min h\u0131z vekt\xf6r\xfc","Negatif de\u011ferler reverse'e izin verir. allow_reversing ile uyumlu olmal\u0131.",null,null,null,null,"H\u0131z Cap")
B.a2D=new A.br("Max ivme vekt\xf6r\xfc","Pozitif ivmelenme cap'leri. Format: [vx m/s\xb2, vy (0), wz rad/s\xb2]. D\xfc\u015f\xfck de\u011fer \u2192 daha yumu\u015fak h\u0131zlanma, snake azal\u0131r. \xc7ok d\xfc\u015f\xfck \u2192 goal'a yeti\u015femez.","Liste \u2014 d\xfc\u015f\xfck: yumu\u015fak, y\xfcksek: keskin",null,null,null,"\u0130vme")
B.a2C=new A.br("Max fren vekt\xf6r\xfc","Negatif olmal\u0131! Yava\u015flama cap'leri. \xc7ok agresif (-3.0) \u2192 goal yak\u0131n\u0131nda servo jitter. \xc7ok yumu\u015fak \u2192 goal'da overshoot.","Negatif de\u011ferler \u2014 fren \u015fiddeti",null,null,null,"\u0130vme")
B.a2Q=new A.br("Smoothing frekans\u0131","Smoother'\u0131n \xe7al\u0131\u015fma frekans\u0131 (Hz). Controller frequency (20Hz) ile uyumlu olmal\u0131.","\u2191 daha tepki, \u2193 CPU tasarrufu","Hz",10,30,"Sistem")
B.a0w=new A.bP(B.a1r,[B.a37,B.a2Z,B.a2D,B.a2C,B.a2Q],t.h_)
B.yT={"inflation_layer.inflation_radius":0,"inflation_layer.cost_scaling_factor":1}
B.a2N=new A.br("Inflation yar\u0131\xe7ap\u0131 (global)",'Engel etraf\u0131na eklenen "ka\xe7\u0131n\u0131lacak alan" yar\u0131\xe7ap\u0131. Y\xfcksek \u2192 planner \xe7ok defensif, dar alanlardan ge\xe7emez. D\xfc\u015f\xfck \u2192 engele yak\u0131n plan \xfcretir (controller takip edemeyebilir). Robot footprint\'ten biraz b\xfcy\xfck tut (5-10cm iyi).',"\u2191 defensif planlama, \u2193 tight ge\xe7i\u015f","m",0.02,0.3,"Inflation")
B.a2P=new A.br("Cost decay (global)","Inflation cost'unun engelden uzakla\u015ft\u0131k\xe7a ne kadar h\u0131zl\u0131 d\xfc\u015ft\xfc\u011f\xfc. Y\xfcksek \u2192 cost h\u0131zla d\xfc\u015fer (gradient sharp). D\xfc\u015f\xfck \u2192 uzun mesafeye yay\u0131l\u0131r (smooth).","\u2191 cost gradient sharp, \u2193 smooth ama uzun yay\u0131l\u0131m",null,1,10,"Inflation")
B.a0o=new A.bP(B.yT,[B.a2N,B.a2P],t.h_)
B.a2I=new A.br("Inflation yar\u0131\xe7ap\u0131 (local)","Local costmap'in inflation yar\u0131\xe7ap\u0131. Controller (RPP) bu cost'u takip eder. Global ile uyumlu olmal\u0131 (genelde ayn\u0131 de\u011fer).","\u2191 wall'dan defensif uzakl\u0131k, \u2193 tight ge\xe7i\u015f","m",0.02,0.3,"Inflation")
B.a2k=new A.br("Cost decay (local)","Local costmap inflation cost gradient'i. RPP'nin cost-regulated velocity scaling'i buradan etkilenir. Y\xfcksek (\u22658) \u2192 cost-induced snake. D\xfc\u015f\xfck (5-6) \u2192 smooth.","\u2193 smooth velocity response, \u2191 keskin cost cliff",null,3,10,"Inflation")
B.a0p=new A.bP(B.yT,[B.a2I,B.a2k],t.h_)
